// Attempt at generating an invoice from purchase order
fn generate_invoice(po: &PurchaseOrder) -> Invoice {
  let mut items = vec![];
  for item in &po.items {
    items.push(InvoiceItem {
      description: item.description.clone(),
      quantity: item.quantity,
      price_per_unit: item.price_per_unit,
    });
  }
  Invoice { order_id: po.order_id.clone(), total_amount: calculate_total(&items), items }
}

// Calculate total amount
fn calculate_total(items: &[InvoiceItem]) -> f64 {
  let mut sum = 0.0;
  for item in items.iter() {
    sum += item.price_per_unit * item.quantity as f64;
  }
  sum
}

